import {
  addToast,
  buildTenantRequestHeaders,
  getAuthToken,
} from '@linm-soft-org/linm-web-common-components';
import { store } from '../store/store';

function buildQs(params: Record<string, string | number | boolean | undefined>) {
  const qs = new URLSearchParams();
  Object.entries(params).forEach(([k, v]) => {
    if (v !== undefined && v !== '') qs.set(k, String(v));
  });
  return qs.toString();
}

function triggerDownload(blob: Blob, fileName: string): void {
  const objectUrl = window.URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = objectUrl;
  link.download = fileName;
  document.body.appendChild(link);
  link.click();
  link.remove();
  window.URL.revokeObjectURL(objectUrl);
}

/** GET export-excel with JWT + X-Company-Id (path relative to VITE_API_URL). */
export async function exportExcel(
  path: string,
  params: Record<string, string | number | boolean | undefined>,
  fileName: string,
): Promise<void> {
  const qs = buildQs(params);
  const base = (import.meta.env.VITE_API_URL ?? '').replace(/\/$/, '');
  const url = `${base}${path.startsWith('/') ? path : `/${path}`}${qs ? `?${qs}` : ''}`;
  const headers = buildTenantRequestHeaders();
  const token = getAuthToken();
  if (token) headers.Authorization = `Bearer ${token}`;

  try {
    const response = await fetch(url, { method: 'GET', headers });
    if (!response.ok) {
      let message = 'Xuất Excel thất bại';
      try {
        const body = await response.json();
        message = body?.error?.toastMessage ?? body?.message ?? message;
      } catch {
        /* ignore */
      }
      throw new Error(message);
    }
    const blob = await response.blob();
    triggerDownload(blob, fileName);
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Xuất Excel thất bại';
    store.dispatch(addToast({ message, type: 'error' }));
    throw err;
  }
}

export function monthStartEnd(): { fromDate: string; toDate: string } {
  const now = new Date();
  const from = new Date(now.getFullYear(), now.getMonth(), 1);
  const to = new Date(now.getFullYear(), now.getMonth() + 1, 0);
  return {
    fromDate: from.toISOString().slice(0, 10),
    toDate: to.toISOString().slice(0, 10),
  };
}

export function yearStartEnd(): { fromDate: string; toDate: string } {
  const y = new Date().getFullYear();
  return { fromDate: `${y}-01-01`, toDate: `${y}-12-31` };
}

export const MONTH_OPTIONS = Array.from({ length: 12 }, (_, i) => ({
  value: String(i + 1),
  label: `T${i + 1}`,
}));

export const YEAR_OPTIONS = [2025, 2026, 2027].map(y => ({
  value: String(y),
  label: String(y),
}));
